import React, { useState, useEffect, useRef } from 'react';
import { clientAPI } from '../../services/clientAPI';

const DOC_TYPES = [
  { value: 'politique_securite', label: 'Politique de sécurité' },
  { value: 'bilan_financier', label: 'Bilan financier' },
  { value: 'plan_continuite', label: 'Plan de continuité' },
  { value: 'certificat_assurance', label: 'Certificat d\'assurance' },
  { value: 'rapport_audit', label: 'Rapport d\'audit' },
  { value: 'autre', label: 'Autre' },
];

export default function ClientDocuments() {
  const [documents, setDocuments] = useState([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [typeDoc, setTypeDoc] = useState('autre');
  const fileRef = useRef();

  const load = async () => {
    setLoading(true);
    setError('');
    try {
      const res = await clientAPI.getDocuments();
      setDocuments(res.data.documents);
      setTotal(res.data.total);
    } catch {
      setError('Impossible de charger les documents');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { load(); }, []);

  const handleUpload = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploading(true);
    setError('');
    setSuccess('');
    try {
      await clientAPI.uploadDocument(file, typeDoc);
      setSuccess(`"${file.name}" uploadé avec succès`);
      load();
    } catch (err) {
      setError(err.response?.data?.detail || 'Erreur lors de l\'upload');
    } finally {
      setUploading(false);
      if (fileRef.current) fileRef.current.value = '';
    }
  };

  return (
    <div>
      {success && (
        <div className="cli-success">
          <i className="ti ti-circle-check" style={{ fontSize: 18 }} />
          {success}
        </div>
      )}
      {error && <div style={{ color: '#ff6680', fontSize: 13, marginBottom: 12 }}>{error}</div>}

      {/* Upload zone */}
      <div style={{ marginBottom: 16 }}>
        <label style={{ fontSize: 12, color: 'var(--cli-muted)', marginBottom: 6, display: 'block', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
          Type de document
        </label>
        <select
          value={typeDoc}
          onChange={(e) => setTypeDoc(e.target.value)}
          style={{
            padding: '9px 14px',
            background: 'var(--cli-card)',
            border: '1px solid var(--cli-border)',
            borderRadius: 8,
            color: 'var(--cli-text)',
            fontSize: 14,
            marginBottom: 12,
          }}
        >
          {DOC_TYPES.map((t) => <option key={t.value} value={t.value}>{t.label}</option>)}
        </select>
      </div>

      <div
        className="cli-upload-zone"
        onClick={() => !uploading && fileRef.current?.click()}
        style={{ cursor: uploading ? 'not-allowed' : 'pointer', opacity: uploading ? 0.7 : 1 }}
      >
        <i className="ti ti-cloud-upload" />
        {uploading
          ? <p>Upload en cours...</p>
          : <>
              <p>Cliquer pour sélectionner un fichier</p>
              <small>PDF, DOCX, PNG, JPG — max 10 Mo</small>
            </>
        }
        <input ref={fileRef} type="file" style={{ display: 'none' }} onChange={handleUpload} />
      </div>

      {/* Liste des documents */}
      {loading && <div className="cli-loading"><i className="ti ti-loader" /> Chargement...</div>}

      {!loading && documents.length > 0 && (
        <div>
          <div style={{ fontSize: 12, color: 'var(--cli-muted)', marginBottom: 12, textTransform: 'uppercase', letterSpacing: '0.05em' }}>
            Documents uploadés ({total})
          </div>
          <div className="cli-doc-list">
            {documents.map((doc) => (
              <div key={doc.id_document} className="cli-doc-item">
                <div className="cli-doc-icon">
                  <i className="ti ti-file" />
                </div>
                <div className="cli-doc-info">
                  <div className="doc-name">{doc.nom || 'Document'}</div>
                  <div className="doc-meta">
                    {doc.type} · {doc.taille_ko != null ? `${doc.taille_ko} Ko` : '—'} · {doc.uploaded_at?.slice(0, 10)}
                  </div>
                </div>
                <i className="ti ti-circle-check" style={{ color: '#4DFFB4', fontSize: 18 }} />
              </div>
            ))}
          </div>
        </div>
      )}

      {!loading && documents.length === 0 && (
        <div className="cli-empty">
          <i className="ti ti-files-off" />
          <p>Aucun document uploadé</p>
        </div>
      )}
    </div>
  );
}
